const source = $input.first()?.json ?? {};
const pick = (...values) => values.find((value) => value !== undefined && value !== null && String(value).trim() !== '');
const clean = (value) => {
  const picked = pick(value);
  return picked === undefined ? '' : String(picked).trim();
};
const member = clean(source.member ?? source.query?.member ?? source.params?.member);
const product = clean(source.product ?? source.query?.product ?? source.params?.product);
const venueId = clean(source.venue_id ?? source.venueId ?? source.query?.venue_id ?? source.query?.venueId ?? source.params?.venue_id ?? source.params?.venueId);
const btn = clean(source.btn ?? source.british_tennis_number ?? source.query?.btn ?? source.query?.british_tennis_number ?? source.params?.btn ?? source.params?.british_tennis_number);
const requestSource = clean(source.request_source ?? source.requestSource ?? source.query?.request_source ?? source.query?.requestSource ?? source.params?.request_source ?? source.params?.requestSource) || 'metabase_missing_signup';
return [{ json: { member, product, venue_id: venueId, btn, request_source: requestSource } }];

const created = $('Create Missing Signup Row').first()?.json ?? {};
const batch = $('Execute Create Signup Batch').first()?.json ?? {};
return [{ json: { message: created.message, action: created.action, signup_id: created.signup_id ?? null, member: created.member ?? null, product: created.product ?? null, source: created.source ?? null, batch_message: batch.message ?? null, batch_id: batch.batch_id ?? null, signup_count: batch.signup_count ?? null, response_code: created.response_code ?? 200 } }];

const result = $input.first()?.json ?? {};
const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;')
  .replace(/'/g, '&#39;');
const responseCode = Number(result.response_code ?? 200);
const isSuccess = responseCode >= 200 && responseCode < 300;
const details = [
  ['Action', result.action],
  ['Member', result.member],
  ['Product', result.product],
  ['Signup ID', result.signup_id],
  ['Batch ID', result.batch_id],
  ['Batch Signup Count', result.signup_count],
  ['Source', result.source],
].filter(([, value]) => value !== null && value !== undefined && String(value).trim() !== '');
const extraMessage = result.batch_message && String(result.batch_message).trim() !== '' ? `<p class="note">${escapeHtml(result.batch_message)}</p>` : '';
const detailHtml = details.map(([label, value]) => `<div class="detail"><span>${escapeHtml(label)}</span><strong>${escapeHtml(value)}</strong></div>`).join('');
const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Missing Signup Capture Result</title>
  <style>
    :root {
      color-scheme: light;
      --bg: #f4f7fb;
      --panel: #ffffff;
      --ink: #1f2937;
      --muted: #667085;
      --line: #d7e0ea;
      --success: #166534;
      --success-soft: #ecfdf3;
      --error: #b42318;
      --error-soft: #fef3f2;
      --button: #e9eef5;
    }
    * { box-sizing: border-box; }
    body {
      margin: 0;
      padding: 24px;
      background: linear-gradient(180deg, #fbfdff 0%, var(--bg) 100%);
      color: var(--ink);
      font-family: Lato, Arial, sans-serif;
    }
    .panel {
      max-width: 780px;
      margin: 0 auto;
      background: var(--panel);
      border: 1px solid var(--line);
      border-radius: 18px;
      padding: 28px;
      box-shadow: 0 20px 40px rgba(15, 23, 42, 0.08);
    }
    .badge {
      display: inline-flex;
      padding: 6px 12px;
      border-radius: 999px;
      font-size: 13px;
      font-weight: 700;
      letter-spacing: 0.04em;
      text-transform: uppercase;
      color: ${isSuccess ? 'var(--success)' : 'var(--error)'};
      background: ${isSuccess ? 'var(--success-soft)' : 'var(--error-soft)'};
    }
    h1 {
      margin: 16px 0 8px;
      font-size: 32px;
      line-height: 1.1;
    }
    p {
      margin: 0;
      color: var(--muted);
      line-height: 1.6;
      font-size: 16px;
    }
    .note {
      margin-top: 12px;
    }
    .details {
      display: grid;
      gap: 12px;
      grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
      margin-top: 24px;
    }
    .detail {
      border: 1px solid var(--line);
      border-radius: 14px;
      padding: 14px 16px;
      background: #f8fafc;
    }
    .detail span {
      display: block;
      margin-bottom: 6px;
      color: var(--muted);
      font-size: 13px;
      font-weight: 700;
      text-transform: uppercase;
      letter-spacing: 0.04em;
    }
    .detail strong {
      font-size: 17px;
      line-height: 1.4;
      word-break: break-word;
    }
    .actions {
      display: flex;
      gap: 12px;
      flex-wrap: wrap;
      margin-top: 24px;
    }
    button {
      appearance: none;
      border: 1px solid var(--line);
      border-radius: 999px;
      background: var(--button);
      color: var(--ink);
      font: inherit;
      font-weight: 700;
      padding: 12px 18px;
      cursor: pointer;
    }
  </style>
</head>
<body>
  <main class="panel">
    <span class="badge">${isSuccess ? 'Success' : 'Action needed'}</span>
    <h1>Missing signup capture</h1>
    <p>${escapeHtml(result.message ?? (isSuccess ? 'Signup capture updated.' : 'The request could not be completed.'))}</p>
    ${extraMessage}
    ${detailHtml ? `<section class="details">${detailHtml}</section>` : ''}
    <div class="actions">
      <button type="button" onclick="window.close()">Close</button>
    </div>
  </main>
</body>
</html>`;
return [{ json: { ...result, response_code: responseCode, html } }];
